import { clamp } from "./types.js";

/**
 * @template T
 * @param {T} v
 * @returns {T}
 */
function freezeDeep(v) {
  if (v === null || typeof v !== "object") return v;
  if (Array.isArray(v)) {
    for (let i = 0; i < v.length; i++) {
      const e = v[i];
      if (e && typeof e === "object") freezeDeep(e);
    }
    return Object.freeze(v);
  }
  for (const k of Object.keys(v)) {
    const val = /** @type {Record<string, unknown>} */ (v)[k];
    if (val && typeof val === "object") freezeDeep(val);
  }
  return Object.freeze(v);
}

/** @param {number} v @param {number} a @param {number} d */
function vad(v, a, d) {
  return Object.freeze({
    valence: clamp(v, -1, 1),
    arousal: clamp(a, 0, 1),
    dominance: clamp(d, 0, 1),
  });
}

/** @param {Record<string, number>} o */
function appr(o) {
  const out = /** @type {Record<string, number>} */ ({});
  for (const k of Object.keys(o))
    out[k] = clamp(/** @type {*} */ (o)[k], -1, 1);
  return Object.freeze(out);
}

/** @param {Record<string, number>} o */
function tend(o) {
  const out = /** @type {Record<string, number>} */ ({});
  for (const k of Object.keys(o))
    out[k] = clamp(/** @type {*} */ (o)[k], 0, 1);
  return Object.freeze(out);
}

/** @param {string} expression @param {[number, number]} pulseBpm @param {[number, number]} breathMs @param {string} aura */
function vis(expression, pulseBpm, breathMs, aura) {
  return Object.freeze({
    expression,
    pulseBpm: Object.freeze([...pulseBpm]),
    breathMs: Object.freeze([...breathMs]),
    aura,
  });
}

