/**
 * @param {string} moodId
 */
export function findPrototype(moodId) {
  return MOOD_PROTOTYPES.find((p) => p.id === moodId) || MOOD_PROTOTYPES[0];
}

/**
 * @param {string} group
 */
export function findPrototypesByGroup(group) {
  return MOOD_PROTOTYPES.filter((p) => p.group === group);
}
